import Chip from '@mui/material/Chip';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import API_PATHS from 'lib/http/apiPaths';
import { optionLabelByValue, useParcelOptions, usePersonOptions } from 'features/shared/selectOptionHelpers';

export function CommonDebtsPage() {
  const parcelOptions = useParcelOptions();
  const personOptions = usePersonOptions();

  return (
    <CrudResourceModule
      title="Deudas de Gastos Comunes"
      path={API_PATHS.debtsGc}
      columns={[
        { key: 'parcela', label: 'Parcela', render: (row) => optionLabelByValue(parcelOptions, row.parcela) },
        { key: 'numero_gastos_comunes', label: 'N° GC' },
        { key: 'total_pesos', label: 'Total CLP' },
        {
          key: 'estado_pago',
          label: 'Estado',
          render: (row) => <Chip size="small" label={row.estado_pago} color={row.estado_pago === 'PAGADO' ? 'success' : 'warning'} />
        }
      ]}
      fields={[
        { name: 'parcela', label: 'Parcela', type: 'select', required: true, options: parcelOptions },
        { name: 'persona', label: 'Persona (opcional)', type: 'select', options: personOptions },
        { name: 'fecha_corte', label: 'Fecha corte', type: 'date' },
        { name: 'numero_gastos_comunes', label: 'N° gastos comunes', type: 'number' },
        { name: 'mora_uf', label: 'Mora UF', type: 'number' },
        { name: 'interes_mora_uf', label: 'Interés mora UF', type: 'number' },
        { name: 'total_uf', label: 'Total UF', type: 'number' },
        { name: 'total_pesos', label: 'Total CLP', type: 'number' },
        {
          name: 'estado_pago',
          label: 'Estado pago',
          type: 'select',
          options: [
            { value: 'PENDIENTE', label: 'Pendiente' },
            { value: 'PARCIAL', label: 'Parcial' },
            { value: 'PAGADO', label: 'Pagado' },
            { value: 'VENCIDO', label: 'Vencido' },
            { value: 'SIN_INFO', label: 'Sin información' }
          ]
        },
        { name: 'observaciones', label: 'Observaciones', type: 'textarea', fullWidth: true }
      ]}
      defaultOrdering="-created_at"
    />
  );
}

